//! Integration-constraint VCs, one per connected port pair whose
//! destination in-port has an integration assume. Each states that the
//! sender's integration guarantee on the source out-port (or `true`, when
//! the sender declares none) implies the receiver's integration assume on
//! the destination in-port, over the value the connection carries. Static
//! (schedule- and property-independent) -- shared by the whole composition.
//! Each proof fn has an empty body: Verus discharges `requires ==> ensures`
//! via SMT; add proof hints in the body if a VC does not discharge.

#![allow(non_snake_case)]
#![allow(unused_variables)]
#![allow(unused_imports)]

use data::*;
use vstd::prelude::*;

use crate::contracts::*;

verus! {

/** VC[0]: Integration -- connection Isolette_Single_Sensor_Instance_operator_interface.oip.oit.lower_alarm_tempWstatus -> thermostat.mt.mmi.mmi.lower_alarm_tempWstatus: oi.lower_alarm_tempWstatus's I-Guar `Allowed_LowerAlarmTempWstatus`
  * implies mmi.lower_alarm_tempWstatus's I-Assm `Allowed_LowerAlarmTemp`, over
  * the value the connection carries. Discharges when the sender's
  * guarantee is at least as strong as the receiver's assume. */
pub proof fn vc_integration_oi_lower_alarm_tempWstatus_to_mmi_lower_alarm_tempWstatus(wire: Isolette_Data_Model::TempWstatus_i)
  requires
    oi::integration_spec_Allowed_LowerAlarmTempWstatus_guarantee(wire),
  ensures
    mmi::integration_spec_Allowed_LowerAlarmTemp_assume(wire),
{}

/** VC[1]: Integration -- connection Isolette_Single_Sensor_Instance_operator_interface.oip.oit.upper_alarm_tempWstatus -> thermostat.mt.mmi.mmi.upper_alarm_tempWstatus: oi.upper_alarm_tempWstatus's I-Guar `Allowed_UpperAlarmTempWstatus`
  * implies mmi.upper_alarm_tempWstatus's I-Assm `Allowed_UpperAlarmTemp`, over
  * the value the connection carries. Discharges when the sender's
  * guarantee is at least as strong as the receiver's assume. */
pub proof fn vc_integration_oi_upper_alarm_tempWstatus_to_mmi_upper_alarm_tempWstatus(wire: Isolette_Data_Model::TempWstatus_i)
  requires
    oi::integration_spec_Allowed_UpperAlarmTempWstatus_guarantee(wire),
  ensures
    mmi::integration_spec_Allowed_UpperAlarmTemp_assume(wire),
{}

} // verus!
